-- 008: 新增维护备注字段 + 刷新频率块划分数据（来源：通道分配状态 2026-06-02）

-- 新增维护备注字段
ALTER TABLE `frequency_block_realtime_status`
  ADD COLUMN `remarkFulfillment` TEXT NULL COMMENT '维护备注-履约状态',
  ADD COLUMN `remarkUser` TEXT NULL COMMENT '维护备注-用户',
  ADD COLUMN `remarkSales` TEXT NULL COMMENT '维护备注-销售';

-- 清除旧数据（bandwidth_usage_record 无数据，无外键冲突）
DELETE FROM `frequency_block_realtime_status`;


-- 解析 switchId
UPDATE `frequency_block_realtime_status` fb
JOIN `matrix_switch_status` sw ON sw.`switchCode` = fb.`switchCode`
SET fb.`switchId` = sw.`id`;

-- 修复 contract_record 频率块外键引用
UPDATE `contract_record` c
JOIN `frequency_block_realtime_status` f ON f.`frequencyBlockCode2` = c.`frequencyBlockCode2`
SET c.`frequencyBlockId` = f.`id`;
